// ========================================
// STEP 2 — CLEAN + SAFE PREPARE DATA NODE
// ========================================

// Incoming request
const userMessage = $input.item.json.body.message || "";
const onboardingData = $input.item.json.body.onboardingData || {};
const checklist = $input.item.json.body.checklist || {};
const conversationHistoryIn = $input.item.json.body.conversationHistory || [];

// --- 1. Sanitize conversation history ---
const conversationHistory = (conversationHistoryIn || [])
  .filter(m => m && m.role && m.content)
  .map(m => ({ role: m.role, content: String(m.content) }));

// --- 2. Build system prompt ---
const systemPrompt = `
You are Tradedoubler’s AI Onboarding Assistant. Speak warmly, ask one question at a time, and acknowledge progress clearly.

Onboarding steps:
1. Branded tracking domains (visit.* + statics.*)
2. Product feed URL (CSV / XML)
3. Program assets (logo, banners, T&Cs)
4. Office IP addresses
5. Tracking scripts implementation

NEVER mark a step complete unless the data is actually provided.

Current collected data:
${JSON.stringify(onboardingData, null, 2)}
Checklist status:
${JSON.stringify(checklist, null, 2)}
`;

// --- 3. Build final messages array ---
const messages = [
  { role: "system", content: systemPrompt },
  ...conversationHistory,
  { role: "user", content: userMessage }
];

return {
  messages,
  userMessage,
  onboardingData,
  checklist,
  uploadedFiles: $input.item.json.body.uploadedFiles || {}
};

// ========================================
// STEP 3 — SMART PROCESS DATA NODE
// ========================================

const aiResponse = $input.item.json.choices[0].message.content;
const userMessage = $('Prepare Data').item.json.userMessage;
const previous = $('Prepare Data').item.json.onboardingData || {};
const uploadedFiles = $('Prepare Data').item.json.uploadedFiles || {};
const lower = userMessage.toLowerCase();

let data = { ...previous };

// ------------------------------------------------
// 1. Extract Name (multi-word)
// ------------------------------------------------
const nameMatch = userMessage.match(/(?:i'?m|i am|my name is)\s+([a-zA-Z][a-zA-Z\s'-]+)/i);
if (nameMatch && !data.clientName) {
    data.clientName = nameMatch[1].trim();
}

// ------------------------------------------------
// 2. Extract Company
// ------------------------------------------------
const companyMatch = userMessage.match(/(?:company|from|we are)\s+(?:called\s+)?([a-zA-Z0-9&\s'-]+)/i);
if (companyMatch && !data.companyName) {
    data.companyName = companyMatch[1].trim();
}

// ------------------------------------------------
// 3. Extract Email
// ------------------------------------------------
const emailMatch = userMessage.match(/[\w.-]+@[\w.-]+\.\w+/);
if (emailMatch) data.email = emailMatch[0];

// ------------------------------------------------
// 4. Extract DNS Subdomains
// ------------------------------------------------
const visitMatch = userMessage.match(/visit\.([a-zA-Z0-9.-]+\.[a-zA-Z]{2,})/);
const staticsMatch = userMessage.match(/statics\.([a-zA-Z0-9.-]+\.[a-zA-Z]{2,})/);

if (visitMatch || staticsMatch) {
    data.brandedTracking = {
        visit: visitMatch ? visitMatch[0] : previous.brandedTracking?.visit || "",
        statics: staticsMatch ? staticsMatch[0] : previous.brandedTracking?.statics || ""
    };
}

// ------------------------------------------------
// 5. Extract Product Feed URL
// ------------------------------------------------
const urlMatch = userMessage.match(/https?:\/\/\S+/);
if (urlMatch) data.productFeedUrl = urlMatch[0];

// ------------------------------------------------
// 6. Extract IP Addresses
// ------------------------------------------------
const ips = userMessage.match(/\b(?:\d{1,3}\.){3}\d{1,3}\b/g);
if (ips) {
    data.officeIPs = [...new Set([...(data.officeIPs || []), ...ips])];
}

// ------------------------------------------------
// 7. ASSET UPLOAD TRIGGER (Option B)
// ------------------------------------------------
let triggerAssetUpload = false;
let assetPayload = null;

const totalFiles =
    (uploadedFiles.logo?.length || 0) +
    (uploadedFiles.banners?.length || 0) +
    (uploadedFiles.terms?.length || 0) +
    (uploadedFiles.other?.length || 0);

if (totalFiles > 0 && lower.includes("upload")) {
    triggerAssetUpload = true;
    assetPayload = {
        logo: uploadedFiles.logo || [],
        banners: uploadedFiles.banners || [],
        terms: uploadedFiles.terms || [],
        other: uploadedFiles.other || []
    };
}

// ------------------------------------------------
// 8. CHECKLIST (data-driven)
// ------------------------------------------------
const checklist = {
    intro: !!(data.clientName && data.companyName),
    brandedTracking: !!(data.brandedTracking?.visit && data.brandedTracking?.statics),
    productFeed: !!data.productFeedUrl,
    assets: totalFiles > 0 || previous.filesUploaded === true,
    ipAddresses: (data.officeIPs || []).length > 0,
    trackingScripts: data.brandedTracking?.visit && data.brandedTracking?.statics && lower.includes("scripts")
};

const isComplete = Object.values(checklist).every(v => v);

// Return everything
return {
  response: aiResponse,
  onboardingData: data,
  checklist,
  triggerAssetUpload,
  assetPayload,
  isComplete
};
